const item = $input.first().json;
const raw = item.output || item.text || item.response || item.message || '{}';
const cleaned = String(raw).trim().replace(/^```json\s*/i, '').replace(/^```/, '').replace(/```$/, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  parsed = {
    account_name: item.account_name || item.accountName || item.recordSummary || 'Unknown Account',
    priority: 'watch',
    briefing_title: item.account_name || item.accountName || 'Market Research Brief',
    research_summary: cleaned || 'No structured research summary returned.',
    external_signals: [],
    opportunity_indicators: [],
    risk_indicators: [],
    recommended_action: 'Review the research packet manually.',
    owner_name: item.owner || item.accountOwner || ''
  };
}
const priority = ['urgent', 'high', 'watch'].includes(String(parsed.priority || '').toLowerCase())
  ? String(parsed.priority).toLowerCase()
  : 'watch';
const asArray = (value) => Array.isArray(value) ? value.filter(Boolean).slice(0, 3) : [];
return [{ json: {
  ...item,
  account_name: parsed.account_name || item.account_name || item.accountName || 'Unknown Account',
  owner_name: parsed.owner_name || item.owner || item.accountOwner || '',
  priority,
  briefing_title: parsed.briefing_title || item.account_name || item.accountName || 'Market Research Brief',
  research_summary: parsed.research_summary || 'No research summary returned.',
  external_signals: asArray(parsed.external_signals),
  opportunity_indicators: asArray(parsed.opportunity_indicators),
  risk_indicators: asArray(parsed.risk_indicators),
  recommended_action: parsed.recommended_action || 'Review the research packet manually.',
  analysis_json: parsed
} }];

const items = $input.all().map((entry) => entry.json);
const config = items[0] || {};
const rank = { urgent: 0, high: 1, watch: 2 };
items.sort((left, right) => (rank[left.priority] ?? 3) - (rank[right.priority] ?? 3));
const buckets = { urgent: [], high: [], watch: [] };
for (const item of items) {
  const bucket = buckets[item.priority] || buckets.watch;
  bucket.push(item);
}
const labels = [
  ['urgent', '🔴 Urgent'],
  ['high', '🟠 High Priority'],
  ['watch', '🟡 Watch List']
];
const sections = [];
for (const [key, label] of labels) {
  const entries = buckets[key];
  if (!entries.length) continue;
  const lines = entries.flatMap((item) => {
    const signalLines = item.external_signals.map((line) => `  External: ${line}`);
    const opportunityLines = item.opportunity_indicators.map((line) => `  Opportunity: ${line}`);
    const riskLines = item.risk_indicators.map((line) => `  Risk: ${line}`);
    return [
      `• *${item.account_name}* | ${item.owner_name || 'Owner TBD'}`,
      `  ${item.research_summary}`,
      ...signalLines,
      ...opportunityLines,
      ...riskLines,
      `  👉 ${item.recommended_action}`,
    ];
  });
  sections.push([`*${label}*`, ...lines].join('\n'));
}
const reportDate = new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
const headline = items.length
  ? `🧠 *Market Research Brief* — ${items.length} account${items.length === 1 ? '' : 's'} with market-moving signals`
  : '🧠 *Market Research Brief* — no material market signals this week';
const slackBody = [headline, reportDate, '', ...(sections.length ? sections : ['No target accounts surfaced material market changes this run.']), '', '_Powered by Backstory MCP — deterministic delivery_'].join('\n');
const escapeHtml = (value) => String(value).replace(/[&<>]/g, (char) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' }[char]));
const htmlSections = sections.length
  ? sections.map((section) => `<pre>${escapeHtml(section)}</pre>`).join('')
  : '<p>No target accounts surfaced material market changes this run.</p>';
const htmlEmail = `<h2>Market Research Brief</h2><p>${reportDate}</p>${htmlSections}<p><em>Powered by Backstory MCP — deterministic delivery</em></p>`;
return [{ json: {
  workflow_id: '30-market-research-brief',
  workflow_name: 'Market Research Brief',
  delivery_channel_id: config.default_channel_id || '',
  summary_email: config.summary_email || '',
  from_email: config.from_email || 'success@backstory.ai',
  slack_body: slackBody,
  email_subject: `Market Research Brief — ${items.length} account${items.length === 1 ? '' : 's'} to review`,
  html_email: htmlEmail,
  plain_text: slackBody,
  brief_count: items.length
} }];
